import numpy as np
from rory.core.utils.utils import Utils
from rory.core.security.cryptosystem.liu import Liu
from typing import List
import numpy.typing as npt
import numpy as np


"""
Description:
A  class to represent a Secure K-Nearest Neighbour (SKNN)
Attributes: 
	D1: Encrypted dataset 
	a: Number of attributes of D1
Variables:
	C: Set of clusters
"""
class SecureKNearestNeighbors:

	"""
	Description: Method for training a model
	"""
	def fit(model:npt.NDArray, model_labels:npt.NDArray):
		pass


	"""
	Description: 
		Method to predict labels to a given dataset.
	Parameters:
		dataset: dataset to be labeled
		model: data model
		model_labels: model labels only
	"""
	@staticmethod
	def predict(dataset:npt.NDArray, model:npt.NDArray, model_labels:npt.NDArray) -> npt.NDArray:
		min_indexes:List[int] = SecureKNearestNeighbors.calculate_distances_and_indexes(
			dataset = dataset,
			model   = model
		)
		label_vector = [ model_labels[index] for index in min_indexes]
		return np.array(label_vector)
	
	"""
	Description:
		Calculates the manhattan distance of a record with respect to the model. 
		It uses homomorphic operations and returns a list with the indices of the 
		smallest distances for each record.
		Manhattan Distance: |x2 - x1| + |y2 - y1| + ... + |xn - x1|
	Parameters:
		model: data models
		dataset: dataset to be labeled
	"""
	@staticmethod
	def calculate_distances_and_indexes(model:npt.NDArray, dataset:npt.NDArray) -> List[int]:
		dataset_shape = Utils.getShapeOfMatrix(dataset)
		model_shape   = Utils.getShapeOfMatrix(model)
		a             = dataset_shape[1]
		mins          = []
		for i in range(dataset_shape[0]):
			distances = []
			for j in range(model_shape[0]):
				manhattan_distance = [0,0,0]
				for k in range(a):
					# S_{i}=|D1 - D2|
					ct_1 = dataset[i][k]
					ct_2 = model[j][k]
					# print("CT_1",ct_1)
					# print("CT_2",ct_2)
					manh = np.abs(
						np.array(
							Liu.subtract(
								ciphertext_1 = ct_1,
								ciphertext_2 = ct_2
								# model[j][k]
							)
						)
					)
					
					# \sum_{k=0}^{a} S_k

					manhattan_distance = Liu.add(
						ciphertext_1 = manhattan_distance,
						ciphertext_2 = manh
					)

				distances.append((j, manhattan_distance))
			xs = list(map(lambda x: (x[0],sum(x[1])), distances) )
			min_xs = min(xs, key=lambda x: x[1])
			mins.append(min_xs[0])
		return mins

	"""
	Description:
		separates an NDArray into data and tags
	Parameters:
		dataset: dataset to be separated
	"""
	@staticmethod
	def split_labelvector_from_data(dataset:npt.NDArray):
		data   = dataset[:, :-1]
		labels = dataset[:, -1]
		return data, labels


